// claim-office.spec.ts
import { describe, it, expect } from "vitest";
import { quote } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Empty / processing fee baseline ---
  it("quote with empty item list returns premium 5 (only the processing fee)", () => {
    expect(quote({ items: [], customerYears: 0, previousContracts: 0 })).toBe(5);
  });

  // --- Base premiums for main items (with processing fee) ---
  it("quote for a single plain sword returns premium 105 (100 base + 5 fee)", () => {
    expect(
      quote({
        items: [{ type: "sword" }],
        customerYears: 0,
        previousContracts: 0,
      }),
    ).toBe(105);
  });
  it("quote for a single plain amulet returns premium 65 (60 base + 5 fee)", () => {
    expect(
      quote({
        items: [{ type: "amulet" }],
        customerYears: 0,
        previousContracts: 0,
      }),
    ).toBe(65);
  });
  it("quote for a single plain staff returns premium 85 (80 base + 5 fee)", () => {
    expect(
      quote({
        items: [{ type: "staff" }],
        customerYears: 0,
        previousContracts: 0,
      }),
    ).toBe(85);
  });
  it("quote for a single plain potion returns premium 45 (40 base + 5 fee)", () => {
    expect(
      quote({
        items: [{ type: "potion" }],
        customerYears: 0,
        previousContracts: 0,
      }),
    ).toBe(45);
  });

  // --- Components and block-of-3 rule ---
  it("quote for 2 runes returns premium 55 (50 base + 5 fee)", () => {
    expect(
      quote({
        items: [{ type: "rune" }, { type: "rune" }],
        customerYears: 0,
        previousContracts: 0,
      }),
    ).toBe(55);
  });
  it("quote for 3 runes returns premium 65 (60 base block + 5 fee)", () => {
    expect(
      quote({
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        customerYears: 0,
        previousContracts: 0,
      }),
    ).toBe(65);
  });
  it("quote for 4 runes returns premium 105 (100 base + 5 fee, no block — block requires exactly 3)", () => {
    expect(
      quote({
        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        customerYears: 0,
        previousContracts: 0,
      }),
    ).toBe(105);
  });
  it("quote for 7 runes returns premium 180 (175 base + 5 fee)", () => {
    expect(
      quote({
        items: [
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
        ],
        customerYears: 0,
        previousContracts: 0,
      }),
    ).toBe(180);
  });
  it("quote for 2 runes + 1 moonstone returns premium 80 (75 base + 5 fee, no block: different types)", () => {
    expect(
      quote({
        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        customerYears: 0,
        previousContracts: 0,
      }),
    ).toBe(80);
  });
  it("quote for 3 runes + 3 moonstones returns premium 125 (120 base + 5 fee, two separate blocks)", () => {
    expect(
      quote({
        items: [
          { type: "rune" },
          { type: "rune" },
          { type: "rune" },
          { type: "moonstone" },
          { type: "moonstone" },
          { type: "moonstone" },
        ],
        customerYears: 0,
        previousContracts: 0,
      }),
    ).toBe(125);
  });

  // --- Item-specific modifiers ---
  it.todo("quote for a cursed sword (steel, ench 3) for newcomer (0 yrs, no previous) returns premium 165");
  it.todo("quote for a sword with enchantment exactly 5 applies the high-enchantment surcharge");
  it.todo("quote for a sword with enchantment 4 does not apply the high-enchantment surcharge");
  it.todo("quote for a cursed sword with enchantment 5 applies both curse and high-enchantment surcharges");

  // --- Policy-wide modifiers ---
  it.todo("quote for a customer with exactly 2 years applies the 20% loyalty discount");
  it.todo("first quote in a scenario applies the 10% first-insurance surcharge");
  it.todo("second quote in a scenario applies the 15% follow-up contract discount");

  // --- Modifier scope on multi-item policies ---
  it.todo("quote for cursed sword + plain amulet: curse surcharge is 50G (50% of cursed item's base, not policy total) → 215G (210 + 5 fee)");

  // --- Rounding ---
  it.todo("premium calculation yielding 197.5 rounds up to 198 (in MHPCO's favor)");

  // --- Integration: long-standing customer's second contract ---
  it.todo("quote for cursed sword (steel, ench 7) for 3-yr customer's second quote returns premium 160");

  // --- Claim: standard reimbursement ---
  it.todo("claim on regular sword (steel, ench 3) with damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("claim on a rune (insurance 250, no enchantment/material) with damage 200 → payout 100 (full minus deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("claim with damage to insured sword (500) and insured amulet (300) → payout 600 (deductible applies once per item)");

  // --- Claim: enchantment threshold ---
  it.todo("claim on steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");

  // --- Claim: dragon material ---
  it.todo("claim on dragon-material sword ench 5, damage 800 → payout 700 (full reimbursement then deductible)");

  // --- Claim: enchantment vs dragon material (50% rule wins) ---
  it.todo("claim on dragon-material sword ench 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
  it.todo("claim on dragon-material sword ench 8, damage 1000 → payout 400 (high-enchantment clause applies, then deductible)");

  // --- Claim: payout rounding ---
  it.todo("payout calculation yielding 350.5 rounds down to 350 (in MHPCO's favor)");

  // --- Multiple items of the same type ---
  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
  it.todo("dragon attack damaging both swords (two sword entries) treats each as separate damage with own deductible");

  // --- Cap ---
  it.todo("policy covering sword + amulet has insurance sum 1600 and cap 3200");
  it.todo("cap is based on unmodified insurance value: cursed sword has cap 2000 regardless of premium modifiers");
  it.todo("policy covering sword + 3 runes has insurance sum 1750 (block discount affects premium only, not insurance sum)");

  // --- Cap exhaustion across successive claims ---
  it.todo("sword (cap 2000): first claim 1500 → payout 1400, remaining cap 600");
  it.todo("sword (cap 2000): second claim 1500 after first → payout 600, remaining cap 0 (reduced to remaining cap)");

  // --- Error cases ---
  it.todo("quote with unknown item type causes the CLI to exit with non-zero status and error to stderr");
  it.todo("claim referencing a damage entry whose item is not in the policy causes non-zero exit and stderr error");
  it.todo("claim with more damage entries of a type than insured (e.g. two sword damages, one sword) causes non-zero exit");
  it.todo("claim with a damage entry of negative amount causes non-zero exit and stderr error");
});

