3	export type Item = {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	};
9	
10	export type QuoteInput = {
11	  items: Item[];
12	  customerYears: number;
13	  previousContracts: number;
14	};
15	
16	const PROCESSING_FEE = 5;
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PREMIUM = 60;
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const CURSE_SURCHARGE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
24	const LOYALTY_DISCOUNT_RATE = 0.2;
25	const LOYALTY_YEARS_THRESHOLD = 2;
26	const FOLLOWUP_DISCOUNT_RATE = 0.15;
27	
28	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	function groupByType(items: Item[]): Map<string, Item[]> {
38	  const groups = new Map<string, Item[]>();
39	  for (const item of items) {
40	    const group = groups.get(item.type) ?? [];
41	    group.push(item);
42	    groups.set(item.type, group);
43	  }
44	  return groups;
45	}
46	
47	function premiumForGroup(type: string, group: Item[]): number {
48	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
49	    return COMPONENT_BLOCK_PREMIUM;
50	  }
51	  return group.length * BASE_PREMIUM_BY_TYPE[type];
52	}
53	
54	function modifierRateForItem(item: Item): number {
55	  let rate = 0;
56	  if (item.cursed) {
57	    rate += CURSE_SURCHARGE_RATE;
58	  }
59	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
60	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
61	  }
62	  return rate;
63	}
64	
65	function premiumForModifiedItem(item: Item): number {
66	  const base = BASE_PREMIUM_BY_TYPE[item.type];
67	  return base + base * modifierRateForItem(item);
68	}
69	
70	function hasCursedItem(items: Item[]): boolean {
71	  return items.some((item) => item.cursed);
72	}
73	
74	function hasHighEnchantmentItem(items: Item[]): boolean {
75	  return items.some(
76	    (item) => item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
77	  );
